mapper.select:
SELECT 
FROM t_repair_project_voting
WHERE project_id = #{projectId} AND plan_id = #{planId} AND tenant_id = #{tenantId}

mapper.update:
UPDATE t_repair_project_voting
SET status = 'VOTING', opened_by_user_id = #{openedByUserId}, opened_at = #{openedAt},
    version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE link_id = #{linkId} AND tenant_id = #{tenantId}
  AND status = 'PREPARED' AND version = #{expectedVersion}

UPDATE t_repair_project_voting
SET status = 'SETTLED', result = #{result}, settled_by_user_id = #{settledByUserId},
    settled_at = #{settledAt}, version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE link_id = #{linkId} AND tenant_id = #{tenantId}
  AND status = 'VOTING' AND version = #{expectedVersion}
